/**
 * Table — composable table primitives for React PDF documents.
 *
 * @registryTitle PDF Table
 * @registryDescription Composable PDF table primitives with header, body, rows, cells, widths, and alignment.
 * @registryCategory data
 * @registryDemos basic=Basic, bordered=Bordered
 */

import * as React from "react";
import {
  Children,
  cloneElement,
  isValidElement,
  type ReactElement,
} from "react";
import { View, Text, StyleSheet } from "@react-pdf/renderer";
import type { Style } from "@react-pdf/types";
import {
  mergePdfStyles,
  type PdfStyleInput,
  usePdfTheme,
} from "@/lib/pdf-theme";

export interface PdfTableProps {
  children: React.ReactNode;
  bordered?: boolean;
  striped?: boolean;
  noWrap?: boolean;
  style?: PdfStyleInput;
}

export interface PdfTableSectionProps {
  children: React.ReactNode;
  style?: PdfStyleInput;
}

export interface PdfTableRowProps {
  children: React.ReactNode;
  header?: boolean;
  stripe?: boolean;
  bordered?: boolean;
  style?: PdfStyleInput;
}

export interface PdfTableCellProps {
  children: React.ReactNode;
  width?: number | string;
  align?: "left" | "center" | "right";
  header?: boolean;
  bordered?: boolean;
  style?: PdfStyleInput;
}

function isRowElement(
  child: React.ReactNode
): child is ReactElement<PdfTableRowProps> {
  return isValidElement(child) && child.type === PdfTableRow;
}

function isCellElement(
  child: React.ReactNode
): child is ReactElement<PdfTableCellProps> {
  return isValidElement(child) && child.type === PdfTableCell;
}

export function PdfTable({
  children,
  bordered = false,
  striped = false,
  noWrap = false,
  style,
}: PdfTableProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    table: {
      borderColor: theme.colors.border,
      borderRadius: theme.radii.md,
      borderWidth: bordered ? 1 : 0,
      overflow: "hidden",
      width: "100%",
    } as Style,
  });
  let rowIndex = 0;
  const processedChildren = Children.map(children, (child) => {
    if (!isValidElement(child)) return child;
    const section = child as ReactElement<PdfTableSectionProps>;
    return cloneElement(section, {
      children: Children.map(section.props.children, (rowChild) => {
        if (!isRowElement(rowChild)) return rowChild;
        const stripe =
          striped && !rowChild.props.header && rowIndex++ % 2 === 1;
        return cloneElement(rowChild, { bordered, stripe });
      }),
    });
  });
  return (
    <View wrap={!noWrap} style={mergePdfStyles(styles.table, style)}>
      {processedChildren}
    </View>
  );
}

export function PdfTableHeader({ children, style }: PdfTableSectionProps) {
  return (
    <View minPresenceAhead={60} style={mergePdfStyles(style)}>
      {children}
    </View>
  );
}

export function PdfTableBody({ children, style }: PdfTableSectionProps) {
  return <View style={mergePdfStyles(style)}>{children}</View>;
}

export function PdfTableRow({
  children,
  header = false,
  stripe = false,
  bordered = false,
  style,
}: PdfTableRowProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    row: {
      backgroundColor: header
        ? theme.colors.muted
        : stripe
          ? "#f9fafb"
          : theme.colors.background,
      borderBottomColor: theme.colors.border,
      borderBottomWidth: bordered ? 1 : 0.75,
      flexDirection: "row",
      width: "100%",
    } as Style,
  });
  const processedChildren = Children.map(children, (child) => {
    if (!isCellElement(child)) return child;
    return cloneElement(child, { bordered, header });
  });
  return (
    <View wrap={false} style={mergePdfStyles(styles.row, style)}>
      {processedChildren}
    </View>
  );
}

export function PdfTableCell({
  children,
  width,
  align = "left",
  header = false,
  bordered = false,
  style,
}: PdfTableCellProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    cell: {
      borderRightColor: theme.colors.border,
      borderRightWidth: bordered ? 1 : 0,
      flex: width ? undefined : 1,
      paddingHorizontal: 8,
      paddingVertical: header ? 7 : 8,
      width,
    } as Style,
    text: {
      color: header ? theme.colors.foreground : theme.colors.mutedForeground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.sm,
      fontWeight: header ? 700 : 400,
      lineHeight: 1.35,
      textAlign: align,
    } as Style,
  });
  return (
    <View style={mergePdfStyles(styles.cell, style)}>
      {typeof children === "string" || typeof children === "number" ? (
        <Text style={styles.text}>{children}</Text>
      ) : (
        children
      )}
    </View>
  );
}

/**
 * PDF Theme — shared theme tokens and helpers for edbn/ui PDF components.
 *
 * @registryTitle PDF Theme
 * @registryDescription Theme provider, default tokens, and style helpers for PDF components.
 * @registryVariant pdf
 * @registryType registry:lib
 */

import * as React from "react";
import type { Style } from "@react-pdf/types";

// ---- TYPES -----------------------------------------------------------------

export interface PdfTheme {
  colors: {
    background: string;
    foreground: string;
    mutedForeground: string;
    border: string;
    primary: string;
    primaryForeground: string;
    muted: string;
    destructive: string;
    warning: string;
    success: string;
  };
  spacing: {
    page: number;
    section: number;
    gap: number;
    sm: number;
    md: number;
    lg: number;
  };
  radii: {
    sm: number;
    md: number;
    lg: number;
  };
  typography: {
    fontFamily: string;
    monoFontFamily: string;
    xs: number;
    sm: number;
    base: number;
    lg: number;
    xl: number;
    xxl: number;
  };
}

export type PdfStyleInput = Style | Style[] | null | undefined | false;

// ---- DEFAULT THEME ---------------------------------------------------------

export const defaultPdfTheme: PdfTheme = {
  colors: {
    background: "#ffffff",
    foreground: "#111827",
    mutedForeground: "#6b7280",
    border: "#d1d5db",
    primary: "#2563eb",
    primaryForeground: "#ffffff",
    muted: "#f3f4f6",
    destructive: "#dc2626",
    warning: "#b45309",
    success: "#15803d",
  },
  spacing: {
    page: 36,
    section: 16,
    gap: 10,
    sm: 6,
    md: 10,
    lg: 16,
  },
  radii: {
    sm: 4,
    md: 7,
    lg: 10,
  },
  typography: {
    fontFamily: "Helvetica",
    monoFontFamily: "Courier",
    xs: 8,
    sm: 9,
    base: 10.5,
    lg: 13,
    xl: 18,
    xxl: 28,
  },
};

// ---- CONTEXT ---------------------------------------------------------------

const PdfThemeContext = React.createContext<PdfTheme>(defaultPdfTheme);

export interface PdfThemeProviderProps {
  theme?: Partial<PdfTheme>;
  children: React.ReactNode;
}

function mergeTheme(theme?: Partial<PdfTheme>): PdfTheme {
  if (!theme) return defaultPdfTheme;
  return {
    colors: { ...defaultPdfTheme.colors, ...theme.colors },
    spacing: { ...defaultPdfTheme.spacing, ...theme.spacing },
    radii: { ...defaultPdfTheme.radii, ...theme.radii },
    typography: { ...defaultPdfTheme.typography, ...theme.typography },
  };
}

export function PdfThemeProvider({ theme, children }: PdfThemeProviderProps) {
  const resolvedTheme = React.useMemo(() => mergeTheme(theme), [theme]);
  return (
    <PdfThemeContext.Provider value={resolvedTheme}>
      {children}
    </PdfThemeContext.Provider>
  );
}

export function usePdfTheme(): PdfTheme {
  return React.useContext(PdfThemeContext) ?? defaultPdfTheme;
}

// ---- STYLE HELPERS ---------------------------------------------------------

export function mergePdfStyles(...styles: PdfStyleInput[]): Style[] {
  return styles.flatMap((style) => {
    if (!style) return [];
    return Array.isArray(style) ? style.filter(Boolean) : [style];
  });
}

export function getToneColor(theme: PdfTheme, tone?: string): string {
  switch (tone) {
    case "primary":
      return theme.colors.primary;
    case "muted":
      return theme.colors.mutedForeground;
    case "destructive":
      return theme.colors.destructive;
    case "warning":
      return theme.colors.warning;
    case "success":
      return theme.colors.success;
    default:
      return theme.colors.foreground;
  }
}
